from pydantic_ai import Agent
from typing import List, Dict

class ManagedMemoryAgent(Agent):
    def __init__(self, *args, max_memory_tokens: int = 8000, **kwargs):
        super().__init__(*args, **kwargs)
        self.max_memory_tokens = max_memory_tokens
        self.memory_window: List[Dict] = []

    def add_memory(self, message: Dict):
        self.memory_window.append(message)
        total_tokens = sum(len(m['content']) for m in self.memory_window)
        while total_tokens > self.max_memory_tokens:
            self.memory_window.pop(0)
            total_tokens = sum(len(m['content']) for m in self.memory_window)

from pydantic_ai import tool, AgentSession

@tool
def search_knowledge_base(query: str, session: AgentSession):
    memory_context = session.get_memory_context()
    relevant_docs = [doc for doc in memory_context if query in doc['content']]
    return {'results': relevant_docs[:3]}

agent = Agent(tools=[search_knowledge_base])

from pydantic_ai import StreamingAgent
from pydantic import BaseModel

class ResumableMemory(BaseModel):
    state: dict
    checkpoint_id: str

class StreamingMemoryAgent(StreamingAgent):
    def validate_partial_memory(self, partial: dict) -> bool:
        try:
            ResumableMemory.model_validate(partial)
            return True
        except:
            # Rollback to last checkpoint
            self.memory_state = self.last_valid_checkpoint
            return False
